@using sv_639f284621bd4a1c845d8f9829e0cd4a.Services

<button class="channel-item @(IsActive ? "active" : "")" @onclick="OnClick">
    <div class="channel-info">
        <span class="channel-name"># @Channel.Name</span>
        <span class="channel-desc">@TruncatedDescription</span>
    </div>
    @if (Channel.UnreadCount > 0)
    {
        <span class="unread-badge">@Channel.UnreadCount</span>
    }
</button>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter] public bool IsActive { get; set; }
    [Parameter] public EventCallback<Channel> OnSelected { get; set; }

    private string TruncatedDescription =>
        Channel.Description.Length > 40
            ? Channel.Description[..40] + "…"
            : Channel.Description;

    private Task OnClick() => OnSelected.InvokeAsync(Channel);
}

.channel-item {
    display: flex;
    align-items: center;
    justify-content: space-between;
    width: 100%;
    padding: 8px 12px;
    border: none;
    background: transparent;
    cursor: pointer;
    text-align: left;
    border-radius: 6px;
    transition: background-color 0.15s;
    gap: 8px;
}

.channel-item:hover {
    background-color: rgba(255, 255, 255, 0.08);
}

.channel-item.active {
    background-color: rgba(255, 255, 255, 0.15);
}

.channel-info {
    display: flex;
    flex-direction: column;
    overflow: hidden;
    min-width: 0;
}

.channel-name {
    font-weight: 600;
    color: #e0e0e0;
    font-size: 0.9rem;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.channel-item.active .channel-name {
    color: #fff;
}

.channel-desc {
    font-size: 0.75rem;
    color: #999;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.unread-badge {
    background-color: #e74c3c;
