@using sv_639f284621bd4a1c845d8f9829e0cd4a.Services
@inject IJSRuntime JS

<div class="message-area">
    <div class="area-header">
        <h3># @ChannelName</h3>
        <span class="area-description">@ChannelDescription</span>
    </div>

    <div class="message-list" @ref="messageListRef" @onscroll="HandleScroll">
        @if (isLoadingMore)
        {
            <div class="loading-indicator">Loading older messages…</div>
        }
        @foreach (var message in Messages)
        {
            <MessageItem Message="message"
                         ReplyCount="GetReplyCount(message.Id)"
                         OnOpenThread="() => OnOpenThread.InvokeAsync(message)"
                         OnReact="(emoji) => OnReact.InvokeAsync((message.Id, emoji))" />
        }
    </div>

    <MessageInput Placeholder="@($"Message #{ChannelName}")"
                  OnSubmit="OnSendMessage" />
</div>

@code {
    [Parameter] public string ChannelName { get; set; } = "";
    [Parameter] public string ChannelDescription { get; set; } = "";
    [Parameter] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, int> ThreadReplyCounts { get; set; } = [];
    [Parameter] public bool HasMoreMessages { get; set; }
    [Parameter] public EventCallback<Message> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }

    private ElementReference messageListRef;
    private bool isLoadingMore;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            await ScrollToBottom();
        }
    }

    private int GetReplyCount(int messageId) =>
        ThreadReplyCounts.GetValueOrDefault(messageId);

    private async Task HandleScroll()
    {
        if (!HasMoreMessages || isLoadingMore) return;

        var scrollTop = await JS.InvokeAsync<double>("eval", "document.querySelector('[b-message-area-scroll]')?.scrollTop ?? 1");
        if (scrollTop < 50)
        {
            isLoadingMore = true;
            await OnLoadMore.InvokeAsync();
            isLoadingMore = false;
        }
    }

    private async Task ScrollToBottom()
    {
        await JS.InvokeVoidAsync("eval",
            "setTimeout(() => { const el = document.querySelector('[b-message-area-scroll]'); if (el) el.scrollTop = el.scrollHeight; }, 50)");
    }
}

