@page "/chat"
@layout ChatLayout
@using sv_639f284621bd4a1c845d8f9829e0cd4a.Services
@using sv_639f284621bd4a1c845d8f9829e0cd4a.Components.Layout
@rendermode InteractiveServer
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-container">
    <div class="sidebar-panel">
        <ChannelSidebar Channels="channels"
                        ActiveChannelId="selectedChannel?.Id"
                        OnChannelSelected="SelectChannel" />
    </div>

    <div class="main-panel" style="flex: @(isThreadOpen ? "55" : "80");">
        @if (selectedChannel is not null)
        {
            <MessageArea ChannelName="@selectedChannel.Name"
                         ChannelDescription="@selectedChannel.Description"
                         Messages="messages"
                         ThreadReplyCounts="threadReplyCounts"
                         HasMoreMessages="hasMoreMessages"
                         OnOpenThread="OpenThread"
                         OnReact="HandleReaction"
                         OnSendMessage="SendMessage"
                         OnLoadMore="LoadMoreMessages" />
        }
        else
        {
            <div class="empty-state">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </div>

    @if (isThreadOpen && threadRootMessage is not null)
    {
        <div class="thread-panel-wrapper">
            <ThreadPanel RootMessage="threadRootMessage"
                         ThreadMessages="threadMessages"
                         OnClose="CloseThread"
                         OnSendReply="SendThreadReply" />
        </div>
    }
</div>

@code {
    private List<Channel> channels = [];
    private Channel? selectedChannel;
    private List<Message> messages = [];
    private Dictionary<int, int> threadReplyCounts = [];
    private bool hasMoreMessages = true;
    private int pageSize = 30;

    private bool isThreadOpen;
    private Message? threadRootMessage;
    private List<Message> threadMessages = [];

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannel(channels[0]);
        }
    }

    private async Task SelectChannel(Channel channel)
    {
        selectedChannel = channel;
        messages = [];
        hasMoreMessages = true;
        threadReplyCounts = [];

        CloseThread();

        messages = await ChatService.GetMessagesAsync(channel.Id, 0, pageSize);
        hasMoreMessages = messages.Count >= pageSize;

        await BuildThreadCounts();
        await ChatService.MarkChannelReadAsync(channel.Id);

        // Refresh channel list to update unread counts
        channels = await ChatService.GetChannelsAsync();
    }

    private async Task LoadMoreMessages()
    {
        if (selectedChannel is null || !hasMoreMessages) return;

        var older = await ChatService.GetMessagesAsync(selectedChannel.Id, messages.Count, pageSize);
        hasMoreMessages = older.Count >= pageSize;
        messages.InsertRange(0, older);
        await BuildThreadCounts();
    }

    private async Task SendMessage(string content)
    {
        if (selectedChannel is null) return;

        var msg = await ChatService.SendMessageAsync(selectedChannel.Id, content, null);
        messages.Add(msg);
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Refresh messages to show updated reactions
        if (selectedChannel is not null)
        {
            messages = await ChatService.GetMessagesAsync(selectedChannel.Id, 0, messages.Count);
        }
    }

    private async Task OpenThread(Message rootMessage)
    {
        threadRootMessage = rootMessage;
        threadMessages = await ChatService.GetThreadAsync(rootMessage.Id);
        isThreadOpen = true;
    }

    private void CloseThread()
    {
        isThreadOpen = false;
        threadRootMessage = null;
        threadMessages = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (selectedChannel is null || threadRootMessage is null) return;

        await ChatService.SendMessageAsync(selectedChannel.Id, content, threadRootMessage.Id);
        threadMessages = await ChatService.GetThreadAsync(threadRootMessage.Id);

        // Update reply count in main view
        threadReplyCounts[threadRootMessage.Id] = threadMessages.Count;
    }

    private async Task BuildThreadCounts()
    {
        // Build reply counts for messages that are thread starters
        // (messages that other messages reply to)
        var rootIds = messages
            .Where(m => m.ReplyToId is not null)
            .Select(m => m.ReplyToId!.Value)
            .Distinct();

        foreach (var rootId in rootIds)
        {
            if (!threadReplyCounts.ContainsKey(rootId))
            {
                var thread = await ChatService.GetThreadAsync(rootId);
                threadReplyCounts[rootId] = thread.Count;
            }
        }

        // Also check for messages that we know have threads by fetching
        // thread data for top-level messages
        foreach (var msg in messages.Where(m => m.ReplyToId is null && !threadReplyCounts.ContainsKey(m.Id)))
        {
            var thread = await ChatService.GetThreadAsync(msg.Id);
            if (thread.Count > 0)
            {
                threadReplyCounts[msg.Id] = thread.Count;
            }
        }
    }
}

